import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"医林改错","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/03-医林改错（王清任）.md","filePath":"tcm-data/04-明清/03-医林改错（王清任）.md","lastUpdated":1781084559000}'),o={name:"tcm-data/04-明清/03-医林改错（王清任）.md"};function n(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="医林改错" tabindex="-1">医林改错 <a class="header-anchor" href="#医林改错" aria-label="Permalink to &quot;医林改错&quot;">​</a></h1><blockquote><p>王清任（1768-1831年），河北玉田人 中医解剖学的探索者，活血化瘀大师 代表作：《医林改错》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字勋臣</li><li><strong>生平</strong>：因见古人解剖有误，亲自去义庄、刑场观察尸体，历时42年写成《医林改错》</li><li><strong>学术地位</strong>：<strong>活血化瘀第一人</strong>，善用桃仁、红花、赤芍等</li><li><strong>特点</strong>：所创方剂皆为<strong>活血化瘀</strong>的名方</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-气血理论" tabindex="-1">1. 气血理论 <a class="header-anchor" href="#_1-气血理论" aria-label="Permalink to &quot;1. 气血理论&quot;">​</a></h3><blockquote><p><strong>「治病之要诀，在明白气血。无论外感内伤，所伤者无非气血。」</strong></p></blockquote><h3 id="_2-瘀血致病" tabindex="-1">2. 瘀血致病 <a class="header-anchor" href="#_2-瘀血致病" aria-label="Permalink to &quot;2. 瘀血致病&quot;">​</a></h3><p>王清任认为：<strong>很多疾病（尤其是疑难病）的根源在于瘀血。</strong></p><h3 id="_3-活血化瘀系列方" tabindex="-1">3. 活血化瘀系列方 <a class="header-anchor" href="#_3-活血化瘀系列方" aria-label="Permalink to &quot;3. 活血化瘀系列方&quot;">​</a></h3><p>王清任创制了一系列&quot;逐瘀汤&quot;，按部位逐瘀：</p><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">部位</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>血府逐瘀汤</strong></td><td style="text-align:left;">胸中</td><td style="text-align:left;">胸痛、头痛、胸闷</td></tr><tr><td style="text-align:left;"><strong>通窍活血汤</strong></td><td style="text-align:left;">头面</td><td style="text-align:left;">头痛、脱发、面黑</td></tr><tr><td style="text-align:left;"><strong>膈下逐瘀汤</strong></td><td style="text-align:left;">膈下（肝脾）</td><td style="text-align:left;">腹痛、癥瘕</td></tr><tr><td style="text-align:left;"><strong>少腹逐瘀汤</strong></td><td style="text-align:left;">少腹（盆腔）</td><td style="text-align:left;">痛经、不孕</td></tr><tr><td style="text-align:left;"><strong>身痛逐瘀汤</strong></td><td style="text-align:left;">全身经络</td><td style="text-align:left;">痹证、身痛</td></tr><tr><td style="text-align:left;"><strong>补阳还五汤</strong></td><td style="text-align:left;">半身</td><td style="text-align:left;">中风后遗症</td></tr></tbody></table><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>血府逐瘀汤</strong></td><td style="text-align:left;">桃红四物+四逆散+牛膝桔梗</td><td style="text-align:left;">胸中瘀血</td><td style="text-align:left;">冠心病、胸痛</td></tr><tr><td style="text-align:left;"><strong>补阳还五汤</strong></td><td style="text-align:left;">黄芪、当归、赤芍、川芎、桃仁、红花、地龙</td><td style="text-align:left;">中风半身不遂</td><td style="text-align:left;">脑梗后遗症</td></tr><tr><td style="text-align:left;"><strong>少腹逐瘀汤</strong></td><td style="text-align:left;">小茴香、干姜、延胡索、没药、当归、川芎、官桂、赤芍、蒲黄、五灵脂</td><td style="text-align:left;">少腹瘀血</td><td style="text-align:left;">痛经、盆腔炎</td></tr><tr><td style="text-align:left;"><strong>通窍活血汤</strong></td><td style="text-align:left;">桃仁、红花、赤芍、川芎、老葱、鲜姜、红枣、麝香</td><td style="text-align:left;">头面瘀血</td><td style="text-align:left;">头痛、脱发</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「治病之要诀，在明白气血。」</strong></p></blockquote><blockquote><p><strong>「无论外感内伤，所伤者无非气血。」</strong></p></blockquote><blockquote><p><strong>「气通血活，何患不除。」</strong></p></blockquote><blockquote><p><strong>「立书所以记名，立名所以记方，立方所以治病。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>活血化瘀法被广泛应用于心脑血管病</li><li><strong>补阳还五汤</strong>是中风后遗症的第一方</li><li><strong>少腹逐瘀汤</strong>是妇科瘀血证的常用方</li></ul><h3 id="与患者的关系" tabindex="-1">与患者的关系 <a class="header-anchor" href="#与患者的关系" aria-label="Permalink to &quot;与患者的关系&quot;">​</a></h3><p>患者（男）面色暗沉、头顶有疤 → 提示有瘀血，处方中<strong>丹皮9g</strong>即取王清任&quot;活血行瘀&quot;之意。</p><hr><p><em>本条目为精简框架版。可扩展至五逐瘀汤的临床鉴别使用专题。</em></p>',30)])])}const c=e(o,[["render",n]]);export{x as __pageData,c as default};
